import{c as a,Q as t,j as s,m as i}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"ADR-054 — Fleet i18n strategy: locale overlay parity at 137 × 14","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-054.md","filePath":"adr/ADR-054.md"}'),l={name:"adr/ADR-054.md"};function o(n,e,r,c,h,d){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="adr-054-—-fleet-i18n-strategy-locale-overlay-parity-at-137-×-14" tabindex="-1">ADR-054 — Fleet i18n strategy: locale overlay parity at 137 × 14 <a class="header-anchor" href="#adr-054-—-fleet-i18n-strategy-locale-overlay-parity-at-137-×-14" aria-label="Permalink to &quot;ADR-054 — Fleet i18n strategy: locale overlay parity at 137 × 14&quot;">​</a></h1><blockquote><p>Status · Accepted (retrospective; shipped v0.6.0) Date · 2026-05-15 Closes · RFC-016 OQ-5 TA anchor · §components/fleet/i18n · §contracts/fleet-overlay Related ADRs · ADR-017 (Paraglide-js i18n + locale overlay architecture), ADR-031 (i18n language list + rollout waves), ADR-032 (font + script strategy Wave 1), ADR-033 (translation workflow: LLM-only first-pass), ADR-043 (sr-Cyrl font gate), ADR-044 (CJK fonts Wave 2), ADR-045 (RTL Arabic), ADR-057 (locale override cookie)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Fleet ships <strong>137 entries × 14 locales = 1,918 overlay files</strong> at full parity. That&#39;s almost double the locale-overlay surface of the entire pre-v0.6 missions corpus (37 missions × 14 = 518 files). The naive plan — author every overlay by hand — would have blocked v0.6 ship by months. The alternative — ship en-US only and let the UI fall back — would have violated the &quot;i18n from the start&quot; constraint (TA §constraints) and made fleet a second-class citizen on the 13 non-English locales.</p><p>Three sub-questions had to be resolved:</p><ol><li><strong>What gets translated</strong> — every editorial field, or just the headline name + a short blurb?</li><li><strong>What pipeline</strong> — same Tiangong rollout (ADR-033 LLM-first-pass + argos-translate fallback + manual review) or something fleet-specific?</li><li><strong>Locale fallback</strong> — when a locale overlay is missing, fall back to what?</li></ol><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="overlay-scope-closes-oq-5" tabindex="-1">Overlay scope (closes OQ-5) <a class="header-anchor" href="#overlay-scope-closes-oq-5" aria-label="Permalink to &quot;Overlay scope (closes OQ-5)&quot;">​</a></h3><p>The fleet overlay carries exactly five editorial fields per entry, matching the user-visible surface of the panel:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;saturn-v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Saturn V&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;best_known_for&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Carried every crewed Apollo lunar mission.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;specs_labels&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;height_m&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Height (m)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;payload_lEO_kg&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;LEO payload (kg)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;flights&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;mission_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;apollo11&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;flight_designation_display&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AS-506 · Apollo 11&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;notes&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;First crewed lunar landing.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Locked by <code>static/data/schemas/fleet-overlay.schema.json</code>. The base file (<code>static/data/fleet/&lt;category&gt;/&lt;id&gt;.json</code> per ADR-052) holds everything language-neutral: id, category, agency, country, manufacturer, dates, status, era, epoch, specs values, linked_missions, linked_sites, flights structure (mission_ids + patch paths + crew names + crew roles + crew countries), credit, links.</p><p><strong>What is NOT translated:</strong></p><ul><li><code>specs</code> values (units are universal; &quot;110.6 m&quot; reads identically in every locale).</li><li><code>agency</code> / <code>country</code> / <code>manufacturer</code> — these surface as flag chips + agency badges, not free-text fields.</li><li><code>crew[].name</code> — proper nouns; we do not transliterate names (Neil Armstrong is &quot;Neil Armstrong&quot; on <code>/fleet?id=apollo-csm-block-ii&amp;locale=ja</code>).</li><li><code>crew[].role</code> — partially translated: roles like &quot;Commander&quot; / &quot;Pilot&quot; / &quot;Mission Specialist&quot; come from the Paraglide-js UI strings catalogue (per ADR-017), not from per-entry overlays.</li><li><code>links[]</code> URLs — link <code>label</code> strings translate via ADR-051&#39;s locale fallback chain, not via the fleet overlay.</li></ul><h3 id="pipeline-closes-oq-5" tabindex="-1">Pipeline (closes OQ-5) <a class="header-anchor" href="#pipeline-closes-oq-5" aria-label="Permalink to &quot;Pipeline (closes OQ-5)&quot;">​</a></h3><p>Same as Tiangong rollout per ADR-033 — three phases:</p><ol><li><strong>en-US authored by hand.</strong> The 137 en-US overlays ship as the canonical editorial truth. Every other locale derives from this.</li><li><strong>Wave 1 + 2 locales</strong> (es, fr, de, pt-BR, it, nl, zh-CN, ja, ko, hi, ar, ru) translated by <strong>argos-translate offline NMT</strong> in batch per ADR-033. argos-translate is the explicit fallback when an LLM round-trip is unavailable or undesirable — it ships free, runs locally, and produces consistent technical translations for the specs-heavy fleet vocabulary. Output written by <code>scripts/wave23/apply-translations.ts</code>.</li><li><strong>sr-Cyrl authored manually</strong> per ADR-043 — argos-translate does not ship a Cyrillic Serbian model, and the Latin → Cyrillic transliteration is not mechanical for the technical vocabulary. The 137 sr-Cyrl overlays are hand-authored against the en-US source. Same pattern as Tiangong sr-Cyrl rollout.</li></ol><p><code>scripts/wave23/</code> toolchain (catalog → maps → apply-translations) is reused unchanged from Tiangong; fleet just passed a different content surface through the same pipe.</p><h3 id="locale-fallback-closes-oq-5" tabindex="-1">Locale fallback (closes OQ-5) <a class="header-anchor" href="#locale-fallback-closes-oq-5" aria-label="Permalink to &quot;Locale fallback (closes OQ-5)&quot;">​</a></h3><p>The data client (<code>src/lib/data.ts</code>) applies the standard ADR-017 shallow-merge:</p><ol><li>Fetch base file <code>static/data/fleet/&lt;category&gt;/&lt;id&gt;.json</code> (always present).</li><li>Fetch overlay <code>static/data/i18n/&lt;locale&gt;/fleet/&lt;category&gt;/&lt;id&gt;.json</code> if present.</li><li>Shallow-merge overlay over base — overlay wins for every field it carries.</li><li><strong>If a non-en-US overlay is missing</strong>, fall back to <strong>en-US</strong> (not to the base file) so the entry still shows translated UI strings around it.</li></ol><p>This chain means the corpus degrades gracefully: missing a Korean overlay shows English text on a Korean-UI page, which is strictly better than rendering nothing or rendering a Romanised stub.</p><h3 id="what-ships-at-v0-6-0" tabindex="-1">What ships at v0.6.0 <a class="header-anchor" href="#what-ships-at-v0-6-0" aria-label="Permalink to &quot;What ships at v0.6.0&quot;">​</a></h3><ul><li><strong>en-US: 137/137</strong> (100 %) — full parity, hand-authored.</li><li><strong>Wave 1 (es, fr, de, pt-BR, it, nl): 137/137 × 6 = 822 files</strong> — argos-translate batch, no manual review pass yet.</li><li><strong>Wave 2 (zh-CN, ja, ko, hi, ar, ru): 137/137 × 6 = 822 files</strong> — argos-translate batch.</li><li><strong>sr-Cyrl: 137/137</strong> — manual authoring (per ADR-043).</li></ul><p>Total: <strong>1,918 overlay files</strong> committed to source. Quality varies by locale: en-US is the editorial truth; Wave 1 + 2 are post-edit pending; sr-Cyrl is hand-checked.</p><p>Locale switching honours the <code>orrery_locale</code> cookie per ADR-057.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li><strong>Five-field overlay surface</strong> keeps the per-entry translation cost minimal (~150 words per entry) while still translating everything the user actually reads. Names, dates, specs, and IDs need no translation.</li><li><strong>argos-translate over LLM</strong> for batch translation: free, deterministic, offline, and ADR-033 already committed to this fallback. LLMs for spot-fix only.</li><li><strong>Hand-authored sr-Cyrl</strong> is the only path; pretending argos handles Cyrillic Serbian would produce mis-script output (Latin transliteration on a Cyrillic page).</li><li><strong>en-US fallback (not base file)</strong> keeps the surrounding UI consistent — a Korean user with a missing Korean overlay still sees Korean for &quot;Saturn V&quot; if Wave 2 has it, then Korean UI strings around the panel; falling back to the base file would mix English content with Korean chrome.</li><li><strong>No crew-name translation</strong> is a deliberate honesty rule: Wernher von Braun, Yuri Gagarin, Liu Yang are not transliterations targets; the user sees the name the historical record uses. Roles are translated because they are role labels, not personal identifiers.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>One overlay file for all entries per locale</strong> (rejected) — would have made PRs ugly and made per-entry translation review impossible to scope. Per-entry files match the base-file shape (ADR-017 standard).</li><li><strong>Crowd-sourced translations</strong> (rejected for v0.6) — quality control overhead exceeds the budget for a one-person curator; reconsider post-1.0 if community contribution lands.</li><li><strong>Ship en-US only and rely on browser auto-translate</strong> (rejected) — violates the &quot;i18n from the start&quot; constraint; browser MT is worse than argos for technical vocabulary; defeats the purpose of having a translated UI shell.</li><li><strong>LLM round-trip for every overlay</strong> (rejected for batch) — non-deterministic, costly at 1,918 × ~150 words, and ADR-033 already locks argos as the batch tool.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>100 % overlay parity across 14 locales at v0.6.0 ship — fleet does not lag any other route on i18n coverage.</li><li>argos-translate pipeline is reusable: any future content surface of comparable size (fleet expansion, science encyclopedia, surface hotspot LOD content per RFC-017) routes through the same toolchain.</li><li>Locale fallback is graceful: a missing overlay never shows as a broken or empty panel.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Wave 1 + 2 argos output has not had a manual review pass; translation quality is &quot;MT-first-pass good&quot; — adequate for technical specs, occasionally awkward for editorial prose like <code>best_known_for</code>. Post-edit is tracked in <code>docs/wip/fleet-translation-review.md</code>.</li><li>sr-Cyrl is the bottleneck for any future fleet expansion — every new entry needs hand-authored Cyrillic, no shortcut.</li><li>1,918 files in <code>git</code> are visible in <code>git status</code> after every locale-overlay rebuild; cleanup tooling lives in <code>scripts/wave23/</code> but the noise is real.</li><li>The &quot;names not translated&quot; rule occasionally produces a mixed-script line in CJK locales when a Russian name is romanised in en-US but appears next to Hiragana/Hangul body text. Acceptable per the editorial-honesty rationale, but visually unusual.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Per-entry overlay path: <code>static/data/i18n/&lt;locale&gt;/fleet/&lt;category&gt;/&lt;id&gt;.json</code>. Schema: <code>static/data/schemas/fleet-overlay.schema.json</code>.</li><li>Batch pipeline: <code>scripts/wave23/catalog.ts</code> → <code>scripts/wave23/maps.ts</code> → <code>scripts/wave23/apply-translations.ts</code> (catalog → per-locale maps → apply translations in JSON overlays). Tracked locally in the maintainer&#39;s Claude Code memory for repeatable invocation across releases.</li><li>Locale-override cookie: <code>orrery_locale</code> (ADR-057). UI exposes locale switcher in the top nav.</li><li>Fallback chain validation: handled by <code>scripts/validate-data.ts</code> — every base entry must have an en-US overlay; non-English overlays are optional but warned-on-missing.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-017 — Paraglide-js i18n + locale overlay architecture (the parent pattern).</li><li>ADR-031 — i18n language list and rollout waves.</li><li>ADR-033 — Translation workflow: LLM-only first-pass (argos-translate is the explicit batch fallback this ADR exercises).</li><li>ADR-043 — Serbian Cyrillic font gate for sr-Cyrl.</li><li>ADR-044 — CJK font strategy for Wave 2 locales.</li><li>ADR-045 — RTL strategy for Arabic locale.</li><li>ADR-052 — Fleet schema + bidirectional cross-reference contract.</li><li>ADR-053 — Fleet imagery sourcing.</li><li>ADR-057 — Narrow exception to &quot;no client storage&quot;: one functional cookie for locale override.</li><li>RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries.</li><li>PRD-012 — Spaceflight Fleet product spec.</li></ul>`,38)])])}const g=a(l,[["render",o]]);export{u as __pageData,g as default};
